"use client";

import { notFound, useParams } from "next/navigation";
import products from "@/data/products.json";
import { Container, Page, PageContent } from "@/components/shared/layout";
import { ProductDetail } from "@/components/shared/product-detail";

export default function ProductDetailPage() {
  const params = useParams<{ productId: string }>();
  const product = products.find((item) => item.id === params.productId);

  if (!product) {
    notFound();
  }

  return (
    <Page>
      <PageContent className="px-0 md:px-0 py-8 md:py-10 space-y-0">
        <section>
          <Container max="8xl" className="px-4 md:px-8 space-y-6">
            <ProductDetail product={product} />
          </Container>
        </section>
      </PageContent>
    </Page>
  );
}

src/app/(store-sync)/login/page.tsx.content:
"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import Link from "next/link";
import { Store, Lock, User } from "lucide-react";
import { Container, Page, PageContent } from "@/components/shared/layout";
import { toast } from "sonner";
import accounts from "@/data/accounts.json";

export default function LoginRegisterPage() {
  const router = useRouter();
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const isDevMode = process.env.NODE_ENV === "development";

  const handleLogin = () => {
    const account = accounts.find(
      (item) => item.username === username.trim() && item.password === password,
    );

    if (!account) {
      toast.error("Sai tài khoản hoặc mật khẩu");
      return;
    }

    localStorage.setItem(
      "storesync_session",
      JSON.stringify({
        id: account.id,
        username: account.username,
        role: account.role,
        displayName: account.displayName,
      }),
    );

    toast.success(`Xin chào ${account.displayName}`);
    router.push(account.role === "admin" ? "/admin/orders" : "/dashboard");
  };

  return (
    <Page>
      <PageContent className="px-0 md:px-0 py-8 md:py-10 space-y-0">
        <section>
          <Container max="8xl" className="px-4 md:px-8">
            <div className="w-full min-h-[calc(100vh-220px)] py-6 md:py-10 grid place-items-center">
              <Card className="w-[min(100%,28rem)] min-w-[22rem] border-border shadow-level-2">
                <CardHeader className="space-y-2 text-center pb-6">
                  <div className="mx-auto bg-primary/10 w-16 h-16 rounded-full flex items-center justify-center mb-2">
                    <Store className="text-primary w-8 h-8" />
                  </div>
                  <CardTitle className="text-3xl font-bold text-foreground">StoreSync B2B</CardTitle>
                  <CardDescription className="text-base text-muted-foreground">
                    Hệ thống quản lý đại lý và mua sỉ
                  </CardDescription>
                </CardHeader>

                <CardContent className="space-y-6">
                  {isDevMode && (
                    <div className="p-3 rounded-xl border border-primary/20 bg-primary/5 space-y-2">
                      <p className="text-xs font-bold text-primary">Chọn nhanh tài khoản test (DEV)</p>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                        {accounts.map((account) => (
                          <Button
                            key={account.id}
                            type="button"
                            size="sm"
                            variant="outline"
                            className="h-8 rounded-lg text-xs justify-start px-2.5"
                            onClick={() => {
                              setUsername(account.username);
                              setPassword(account.password);
                            }}
                          >
                            {account.role === "admin" ? "Admin" : "Cửa hàng"} - {account.username}
                          </Button>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className="space-y-3">
                    <Label htmlFor="username" className="text-sm font-medium">Tên đăng nhập</Label>
                    <div className="relative">
                      <User className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                      <Input
                        id="username"
                        type="text"
                        placeholder="Nhập tài khoản"
                        className="pl-10 h-12"
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                      />
                    </div>
                  </div>
                  <div className="space-y-3">
                    <div className="flex justify-between items-center">
                      <Label htmlFor="password-login" className="text-sm font-medium">Mật khẩu</Label>
                      <Link href="/support" className="text-sm text-primary font-medium hover:underline">
                        Quên mật khẩu?
                      </Link>
                    </div>
                    <div className="relative">
                      <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                      <Input
                        id="password-login"
                        type="password"
                        placeholder="Nhập mật khẩu"
                        className="pl-10 h-12"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === "Enter") handleLogin();
                        }}
                      />
                    </div>
                  </div>
                  <Button className="w-full h-12 text-base font-bold mt-6" size="lg" onClick={handleLogin}>
                    Đăng nhập hệ thống
                  </Button>
                  <p className="text-sm text-center text-muted-foreground">
                    Chưa có tài khoản đại lý?{" "}
                    <Link href="/register" className="text-primary font-semibold hover:underline">
                      Đăng ký ngay
                    </Link>
                  </p>
                  {isDevMode && (
                    <p className="text-xs text-muted-foreground bg-muted/30 p-3 rounded-xl">
                      Demo: admin/admin123 (quản trị) hoặc cuahangso1/store123 (chủ cửa hàng)
                    </p>
                  )}
                </CardContent>
              </Card>
            </div>
          </Container>
        </section>
      </PageContent>
    </Page>
  );
}

src/app/(store-sync)/orders/page.tsx.content:
"use client";

import { useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Package, Search, RefreshCw, ChevronDown, Filter, Truck, CheckCircle2, Clock3, Eye, ShoppingCart, Box, FlaskConical } from "lucide-react";
import { Input } from "@/components/ui/input";
import Link from "next/link";
import { Container, Page, PageContent } from "@/components/shared/layout";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import orders from "@/data/order-tracking.json";
import products from "@/data/products.json";

type StatusFilter = "ALL" | "SHIPPING" | "COMPLETED";

const STATUS_FILTER_OPTS: { key: StatusFilter; label: string }[] = [
  { key: "ALL", label: "Tất cả trạng thái" },
  { key: "SHIPPING", label: "Đang giao" },
  { key: "COMPLETED", label: "Đã hoàn thành" },
];

export default function OrdersPage() {
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("ALL");

  const enrichedOrders = useMemo(() =>
    orders.map((order) => ({
      ...order,
      statusKey: order.status === "Đang giao hàng" ? "SHIPPING" : "COMPLETED",
      enrichedItems: order.items.map((item) => ({
        ...item,
        product: products.find((p) => p.id === item.productId),
      })),
    })),
    []
  );

  const filteredOrders = useMemo(() => {
    return enrichedOrders.filter((order) => {
      const matchStatus = statusFilter === "ALL" || order.statusKey === statusFilter;
      const q = searchTerm.trim().toLowerCase();
      const matchSearch =
        !q ||
        order.id.toLowerCase().includes(q) ||
        order.enrichedItems.some((i) =>
          i.product?.name.toLowerCase().includes(q) ||
          i.product?.category.toLowerCase().includes(q)
        );
      return matchStatus && matchSearch;
    });
  }, [enrichedOrders, searchTerm, statusFilter]);

  const statusLabel = STATUS_FILTER_OPTS.find((o) => o.key === statusFilter)?.label ?? "Tất cả";

  const shippingCount = enrichedOrders.filter((o) => o.statusKey === "SHIPPING").length;
  const completedCount = enrichedOrders.filter((o) => o.statusKey === "COMPLETED").length;

  return (
    <Page>
      <PageContent className="px-0 md:px-0 py-8 md:py-10 space-y-0">
        <section>
          <Container max="8xl" className="px-4 md:px-8 space-y-8">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div>
                <h1 className="text-4xl font-extrabold text-foreground tracking-tight flex items-center gap-3">
                  <Package className="w-10 h-10 text-primary" />
                  Đơn hàng của tôi
                </h1>
                <p className="text-lg text-on-surface-variant font-medium mt-1">Theo dõi tiến độ giao nhận – sỉ & lẻ</p>
              </div>
              <Button variant="outline" className="flex items-center gap-2 border-outline-variant h-12 px-6 rounded-xl font-bold hover:bg-muted">
                <RefreshCw className="w-5 h-5" />
                Cập nhật mới nhất
              </Button>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-3 gap-4">
              <div className="bg-surface border border-outline-variant rounded-2xl p-4 text-center">
                <p className="text-3xl font-black text-foreground">{enrichedOrders.length}</p>
                <p className="text-sm text-on-surface-variant font-medium mt-1">Tổng đơn</p>
              </div>
              <div className="bg-primary/5 border border-primary/20 rounded-2xl p-4 text-center">
                <p className="text-3xl font-black text-primary">{shippingCount}</p>
                <p className="text-sm text-primary/70 font-medium mt-1 flex items-center justify-center gap-1"><Truck className="w-3.5 h-3.5" /> Đang giao</p>
              </div>
              <div className="bg-success/5 border border-success/20 rounded-2xl p-4 text-center">
                <p className="text-3xl font-black text-success">{completedCount}</p>
                <p className="text-sm text-success/70 font-medium mt-1 flex items-center justify-center gap-1"><CheckCircle2 className="w-3.5 h-3.5" /> Hoàn thành</p>
              </div>
            </div>

            {/* Search + Filter */}
            <div className="bg-surface p-6 rounded-2xl border border-outline-variant flex flex-col lg:flex-row gap-4 items-center">
              <div className="relative flex-grow w-full">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-outline w-5 h-5" />
                <Input
                  placeholder="Tìm mã đơn, tên sản phẩm, danh mục..."
                  className="pl-12 py-6 text-base bg-background border-outline-variant rounded-xl focus:ring-primary/20"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger render={<Button variant="outline" className="w-full lg:w-auto h-12 rounded-xl border-outline-variant font-semibold" />}>
                  <Filter className="w-4 h-4 mr-2" />
                  {statusLabel}
                  <ChevronDown className="w-4 h-4 ml-2" />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56">
                  {STATUS_FILTER_OPTS.map((opt) => (
                    <DropdownMenuItem key={opt.key} onClick={() => setStatusFilter(opt.key)}>
                      {opt.label}
                    </DropdownMenuItem>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>
            </div>

            {/* Order Cards */}
            <div className="space-y-4">
              {filteredOrders.map((order) => (
                <div key={order.id} className="bg-background border border-outline-variant rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all">
                  {/* Order Header */}
                  <div className={`flex flex-wrap items-center justify-between gap-3 px-6 py-4 border-b border-outline-variant/40 ${order.statusKey === "SHIPPING" ? "bg-primary/5" : "bg-success/5"}`}>
                    <div className="flex items-center gap-3">
                      <span className="font-black text-lg text-primary">{order.id}</span>
                      <span className="text-sm text-on-surface-variant">·</span>
                      <span className="text-sm text-on-surface-variant font-medium flex items-center gap-1">
                        <Clock3 className="w-3.5 h-3.5" />
                        {order.date}
                      </span>
                    </div>
                    <div className="flex items-center gap-3">
                      {order.statusKey === "SHIPPING" ? (
                        <Badge className="bg-primary/15 text-primary border-primary/20 font-bold px-3 py-1">
                          <Truck className="w-3.5 h-3.5 mr-1.5" /> Đang giao hàng
                        </Badge>
                      ) : (
                        <Badge className="bg-success/15 text-success border-success/20 font-bold px-3 py-1">
                          <CheckCircle2 className="w-3.5 h-3.5 mr-1.5" /> Đã hoàn thành
                        </Badge>
                      )}
                      <span className="font-black text-xl text-foreground">{order.total}</span>
                    </div>
                  </div>

                  {/* ETA / Address */}
                  <div className="px-6 py-3 bg-muted/20 border-b border-outline-variant/20 flex flex-wrap gap-4 text-sm text-on-surface-variant">
                    <span className="flex items-center gap-1.5 font-medium">
                      <Truck className="w-4 h-4 text-primary" />
                      {order.eta}
                    </span>
                    <span className="flex items-center gap-1.5 font-medium">
                      <Package className="w-4 h-4 text-primary" />
                      {order.address}
                    </span>
                  </div>

                  {/* Items breakdown */}
                  <div className="px-6 py-4 space-y-2">
                    <p className="text-xs font-bold text-on-surface-variant uppercase tracking-wide mb-3">Chi tiết hàng hóa:</p>
                    {order.enrichedItems.map((item, idx) => (
                      <div key={idx} className="flex items-center justify-between rounded-xl border border-outline-variant/30 bg-surface/50 px-4 py-3">
                        <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-white rounded-lg border border-outline-variant/40 flex items-center justify-center shrink-0 overflow-hidden">
                            {item.product?.primaryImage ? (
                              <img src={item.product.primaryImage} alt="" className="w-full h-full object-contain p-1" />
                            ) : (
                              <Box className="w-5 h-5 text-outline-variant" />
                            )}
                          </div>
                          <div>
                            <p className="font-bold text-sm text-foreground line-clamp-1">{item.product?.name ?? item.productId}</p>
                            <div className="flex items-center gap-2 mt-0.5">
                              <Badge className="text-[10px] px-1.5 py-0 bg-muted text-on-surface-variant border-outline-variant/40">
                                {item.product?.category}
                              </Badge>
                              <span className="text-xs text-on-surface-variant font-medium">
                                {item.unitLabel ?? item.unitType}
                              </span>
                              {item.purchaseType === "si" && (
                                <Badge className="text-[10px] px-1.5 py-0 bg-primary/10 text-primary border-primary/20">Sỉ</Badge>
                              )}
                              {item.purchaseType === "le" && (
                                <Badge className="text-[10px] px-1.5 py-0 bg-secondary/10 text-secondary border-secondary/20">Lẻ</Badge>
                              )}
                            </div>
                          </div>
                        </div>
                        <div className="text-right shrink-0">
                          <p className="font-black text-primary">{item.price}</p>
                          <p className="text-xs text-on-surface-variant">x {item.qty} {item.unitType}</p>
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* Actions */}
                  <div className="px-6 pb-5 flex flex-wrap gap-3 justify-end">
                    <Link href={`/orders/${order.id}`}>
                      <Button variant="outline" size="sm" className="rounded-xl border-outline-variant font-semibold">
                        <Eye className="w-4 h-4 mr-2" /> Chi tiết đơn
                      </Button>
                    </Link>
                    <Link href="/catalog">
                      <Button size="sm" className="rounded-xl font-bold">
                        <ShoppingCart className="w-4 h-4 mr-2" /> Đặt lại
                      </Button>
                    </Link>
                  </div>
                </div>
              ))}
            </div>

            {filteredOrders.length === 0 && (
              <div className="text-center py-20 bg-muted/20 rounded-3xl border border-dashed border-outline-variant">
                <Package className="w-20 h-20 text-outline-variant mx-auto mb-6 opacity-20" />
                <h3 className="text-2xl font-bold text-on-surface-variant">Không có đơn hàng phù hợp</h3>
                <p className="text-outline mt-2">Thử thay đổi từ khóa hoặc bộ lọc trạng thái.</p>
                <Link href="/catalog">
                  <Button className="mt-8 h-14 px-10 text-lg font-bold rounded-xl" size="lg">
                    Đến trang Sản phẩm
                  </Button>
                </Link>
              </div>
            )}
          </Container>
        </section>
      </PageContent>
    </Page>
  );
}

src/app/(store-sync)/orders/[orderId]/pa.content:
"use client";

import Link from "next/link";
import { notFound, useParams } from "next/navigation";
import type { ComponentType } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ArrowLeft, CheckCircle2, CircleDot, Clock3, Package, Truck } from "lucide-react";
import orders from "@/data/order-tracking.json";
import products from "@/data/products.json";
import { Container, Page, PageContent } from "@/components/shared/layout";

export default function OrderDetailPage() {
  const params = useParams<{ orderId: string }>();
  const order = orders.find((item) => item.id === params.orderId);

  if (!order) {
    notFound();
  }

  const isShipping = order.status === "Đang giao hàng";

  return (
    <Page>
      <PageContent className="px-0 md:px-0 py-8 md:py-10 space-y-0">
        <section>
          <Container max="8xl" className="px-4 md:px-8 space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <Link href="/orders">
          <Button variant="outline" className="rounded-xl">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Quay lại danh sách đơn
          </Button>
        </Link>
        <Badge className={isShipping ? "bg-primary/10 text-primary border-primary/20" : "bg-success/10 text-success border-success/20"}>
          {order.status}
        </Badge>
      </div>

      <Card className="rounded-2xl border-outline-variant">
        <CardHeader className="border-b border-outline-variant/40">
          <CardTitle className="text-3xl font-black tracking-tight">Chi tiết đơn {order.id}</CardTitle>
        </CardHeader>
        <CardContent className="p-6 space-y-6">
          <div className="rounded-2xl border border-outline-variant/40 bg-surface/40 p-4">
            <p className="text-sm text-muted-foreground mb-3 font-semibold">Tiến trình đơn hàng</p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
              <TimelineStep label="Đã đặt đơn" active />
              <TimelineStep label="Đang vận chuyển" active={isShipping} />
              <TimelineStep label="Hoàn tất" active={!isShipping} />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <InfoTile icon={Clock3} label="Thời gian đặt" value={order.date} />
            <InfoTile icon={Truck} label="Trạng thái giao hàng" value={order.eta} />
            <InfoTile icon={Package} label="Tổng thanh toán" value={order.total} />
          </div>

          <div className="bg-muted/30 border border-outline-variant/30 rounded-xl p-4">
            <p className="text-sm text-muted-foreground">Địa chỉ nhận hàng</p>
            <p className="text-lg font-bold">{order.address}</p>
          </div>

          <div className="space-y-3">
            {order.items.map((item) => (
              <div key={item.productId} className="flex items-center justify-between rounded-xl border border-outline-variant/30 p-4 hover:bg-muted/20 transition-colors">
                <div>
                  <Link href={`/catalog/${item.productId}`} className="font-bold hover:text-primary transition-colors">
                    {products.find((p) => p.id === item.productId)?.name ?? item.productId}
                  </Link>
                  <p className="text-sm text-muted-foreground">Số lượng: {item.qty}</p>
                </div>
                <p className="font-black text-primary">{item.price}</p>
              </div>
            ))}
          </div>

          <div className="pt-2 flex flex-wrap gap-3">
            <Link href="/catalog">
              <Button className="rounded-xl h-12 font-bold">
                <CheckCircle2 className="w-4 h-4 mr-2" />
                Mua lại từ danh mục
              </Button>
            </Link>
            <Link href="/support">
              <Button variant="outline" className="rounded-xl h-12 font-bold">
                Liên hệ hỗ trợ đơn hàng
              </Button>
            </Link>
          </div>
        </CardContent>
      </Card>
          </Container>
        </section>
      </PageContent>
    </Page>
  );
}

function TimelineStep({ label, active }: { label: string; active?: boolean }) {
  return (
    <div className={`rounded-xl border p-3 flex items-center gap-2 ${active ? "border-primary/40 bg-primary/5 text-primary" : "border-outline-variant/40 text-muted-foreground"}`}>
      <CircleDot className="w-4 h-4" />
      <span className="font-semibold text-sm">{label}</span>
    </div>
  );
}

function InfoTile({
  icon: Icon,
  label,
  value,
}: {
  icon: ComponentType<{ className?: string }>;
  label: string;
  value: string;
}) {
  return (
    <div className="rounded-xl border border-outline-variant/40 bg-surface p-4">
      <p className="text-sm text-muted-foreground flex items-center gap-2">
        <Icon className="w-4 h-4 text-primary" />
        {label}
      </p>
      <p className="mt-2 font-bold">{value}</p>
    </div>
  );
}

src/app/(store-sync)/profile/page.tsx.content:
"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Container, Page, PageContent } from "@/components/shared/layout";
import { ExternalLink, LogOut, MapPin, Navigation, Phone, ShieldCheck, Store } from "lucide-react";
import accounts from "@/data/accounts.json";

type MockSession = {
  id: string;
  username: string;
  role: "admin" | "store";
  displayName: string;
};

type MockAccount = {
  id: string;
  username: string;
  role: "admin" | "store";
  displayName: string;
  phone: string;
  ownerName: string;
  storeName: string;
  address: string;
  mapQuery: string;
  quickAddresses: string[];
};

export default function ProfilePage() {
  const router = useRouter();
  const [session, setSession] = useState<MockSession | null>(null);
  const [selectedAddress, setSelectedAddress] = useState("");

  useEffect(() => {
    const raw = localStorage.getItem("storesync_session");
    if (!raw) {
      router.push("/login");
      return;
    }
    try {
      setSession(JSON.parse(raw));
    } catch {
      router.push("/login");
    }
  }, [router]);

  const handleLogout = () => {
    localStorage.removeItem("storesync_session");
    router.push("/login");
  };

  if (!session) return null;

  const account = accounts.find((item) => item.id === session.id) as MockAccount | undefined;
  const ownerName = account?.ownerName ?? session.displayName;
  const storeName = account?.storeName ?? "Cửa hàng chưa cập nhật";
  const phone = account?.phone ?? "Chưa cập nhật";
  const defaultAddress = account?.address ?? "Chưa cập nhật địa chỉ";
  const quickAddresses = account?.quickAddresses ?? [defaultAddress];
  const currentAddress = selectedAddress || defaultAddress;
  const mapQuery = encodeURIComponent(currentAddress);
  const mapIframeUrl = `https://www.google.com/maps?q=${mapQuery}&output=embed`;
  const mapExternalUrl = `https://www.google.com/maps/search/?api=1&query=${mapQuery}`;

  return (
    <Page>
      <PageContent className="px-0 md:px-0 py-8 md:py-10 space-y-0">
        <section>
          <Container max="8xl" className="px-4 md:px-8">
            <div className="min-h-[60vh] grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
              <Card className="w-full border-outline-variant">
                <CardHeader className="space-y-3">
                  <Badge className="w-fit bg-primary/10 text-primary border-primary/20">
                    {session.role === "admin" ? "Quản trị viên" : "Chủ cửa hàng"}
                  </Badge>
                  <CardTitle className="text-3xl font-black">Trang cá nhân</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="rounded-xl border border-outline-variant/40 p-4 bg-surface/30">
                    <p className="text-sm text-muted-foreground">Tên chủ sở hữu</p>
                    <p className="font-bold text-lg flex items-center gap-2">
                      {session.role === "admin" ? <ShieldCheck className="w-4 h-4 text-primary" /> : <Store className="w-4 h-4 text-primary" />}
                      {ownerName}
                    </p>
                  </div>
                  <div className="rounded-xl border border-outline-variant/40 p-4 bg-surface/30">
                    <p className="text-sm text-muted-foreground">Tên cửa hàng</p>
                    <p className="font-bold text-lg">{storeName}</p>
                  </div>
                  <div className="rounded-xl border border-outline-variant/40 p-4 bg-surface/30">
                    <p className="text-sm text-muted-foreground">Số điện thoại liên hệ</p>
                    <p className="font-bold text-lg flex items-center gap-2">
                      <Phone className="w-4 h-4 text-primary" />
                      {phone}
                    </p>
                  </div>
                  <div className="rounded-xl border border-outline-variant/40 p-4 bg-surface/30">
                    <p className="text-sm text-muted-foreground">Tên đăng nhập</p>
                    <p className="font-bold text-lg">{session.username}</p>
                  </div>
                  <div className="rounded-xl border border-outline-variant/40 p-4 bg-surface/30 space-y-2">
                    <p className="text-sm text-muted-foreground">Địa chỉ cửa hàng</p>
                    <p className="font-bold text-base flex items-start gap-2">
                      <MapPin className="w-4 h-4 text-primary mt-0.5" />
                      {currentAddress}
                    </p>
                  </div>
                  <div className="flex flex-wrap gap-3 pt-2">
                    <Link href={session.role === "admin" ? "/admin/orders" : "/dashboard"}>
                      <Button variant="outline">Về trang làm việc</Button>
                    </Link>
                    <Button variant="destructive" onClick={handleLogout}>
                      <LogOut className="w-4 h-4 mr-2" />
                      Đăng xuất
                    </Button>
                  </div>
                </CardContent>
              </Card>

              <Card className="w-full border-outline-variant">
                <CardHeader className="space-y-2">
                  <CardTitle className="text-2xl font-black flex items-center gap-2">
                    <Navigation className="w-5 h-5 text-primary" />
                    Vị trí cửa hàng trên Google Maps
                  </CardTitle>
                  <p className="text-sm text-muted-foreground">
                    Chọn nhanh địa chỉ mẫu để kiểm tra vị trí hiển thị trên bản đồ.
                  </p>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="flex flex-wrap gap-2">
                    {quickAddresses.map((address) => (
                      <Button
                        key={address}
                        variant={address === currentAddress ? "default" : "outline"}
                        size="sm"
                        className="rounded-lg"
                        onClick={() => setSelectedAddress(address)}
                      >
                        {address}
                      </Button>
                    ))}
                  </div>

                  <div className="rounded-xl overflow-hidden border border-outline-variant/40 bg-muted/20">
                    <iframe
                      title="Google Map cửa hàng"
                      src={mapIframeUrl}
                      className="w-full h-[380px] border-0"
                      loading="lazy"
                      referrerPolicy="no-referrer-when-downgrade"
                    />
                  </div>

                  <Link href={mapExternalUrl} target="_blank" rel="noreferrer">
                    <Button variant="outline" className="w-full">
                      <ExternalLink className="w-4 h-4 mr-2" />
                      Mở Google Maps trong tab mới
                    </Button>
                  </Link>
                </CardContent>
              </Card>
            </div>
          </Container>
        </section>
      </PageContent>
    </Page>
  );
}

