export default function InventoryPage() {
  const [inventory, setInventory] = useState<Product[]>(INITIAL_INVENTORY);
  const [categoryFilter, setCategoryFilter] = useState("ALL");
  const [searchTerm, setSearchTerm] = useState("");
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set());
  const [dialogOpen, setDialogOpen] = useState(false);

  const [modalImages, setModalImages] = useState([
    { id: 1, url: "https://via.placeholder.com/150/006a61/ffffff?text=Ảnh+1", isPrimary: true },
    { id: 2, url: "https://via.placeholder.com/150/eaf1ff/0b1c30?text=Ảnh+2", isPrimary: false },
  ]);

  const toggleExpand = (id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const setPrimaryImage = (id: number) =>
    setModalImages((imgs) => imgs.map((img) => ({ ...img, isPrimary: img.id === id })));

  const handleSave = () => {
    toast.success("Đã lưu sản phẩm thành công!");
    setDialogOpen(false);
  };

  const filtered = inventory.filter((p) => {
    const matchCat = categoryFilter === "ALL" || p.categoryGroup === categoryFilter;
    const q = searchTerm.toLowerCase().trim();
    const matchSearch = !q || p.name.toLowerCase().includes(q) || p.id.toLowerCase().includes(q) || p.brand.toLowerCase().includes(q);
    return matchCat && matchSearch;
  });

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-4xl font-extrabold text-foreground">Quản lý Hàng hóa & Kho</h1>
          <p className="text-on-surface-variant font-medium mt-1">Phân loại danh mục, quản lý đơn vị (thùng / can / chai / lốc / gói) và theo dõi tồn kho</p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger render={<Button className="flex items-center gap-2 shadow-md h-12 px-6 rounded-xl font-bold" />}>
            <Plus className="w-5 h-5" /> Thêm sản phẩm mới
          </DialogTrigger>
          <DialogContent className="sm:max-w-[720px] max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle className="text-2xl font-extrabold">Thêm / Sửa sản phẩm</DialogTitle>
              <DialogDescription>Điền đầy đủ thông tin sản phẩm, chọn danh mục, đơn vị tính và tải ảnh lên.</DialogDescription>
            </DialogHeader>
            <div className="space-y-6 py-2">
              {/* Basic info */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="pname">Tên sản phẩm</Label>
                  <Input id="pname" placeholder="VD: Coca-Cola 320ml" />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="pbrand">Thương hiệu</Label>
                  <Input id="pbrand" placeholder="VD: Coca-Cola" />
                </div>
                <div className="space-y-2">
                  <Label>Danh mục</Label>
                  <Select>
                    <SelectTrigger className="rounded-xl">
                      <SelectValue placeholder="Chọn danh mục" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="do-uong">Nước giải khát</SelectItem>
                      <SelectItem value="thuc-pham">Thực phẩm khô</SelectItem>
                      <SelectItem value="sua-bot">Sữa và chế phẩm</SelectItem>
                      <SelectItem value="gia-vi">Gia vị & Dầu ăn</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label htmlFor="psku">Mã SKU</Label>
                  <Input id="psku" placeholder="VD: CC-320-24" />
                </div>
              </div>

              {/* Unit types */}
              <div className="border border-outline-variant rounded-xl p-4 space-y-3 bg-muted/10">
                <p className="font-bold text-sm text-foreground">Đơn vị tính & Giá theo loại hàng</p>
                <p className="text-xs text-on-surface-variant">Định nghĩa các đơn vị bán (thùng, can, chai, lốc, gói...) cùng giá sỉ và giá lẻ tương ứng.</p>
                {(["thùng", "can", "chai"] as const).map((unit) => (
                  <div key={unit} className="grid grid-cols-3 gap-3 items-end">
                    <div className="space-y-1">
                      <Label className="text-xs capitalize">{unit.charAt(0).toUpperCase() + unit.slice(1)} – Mô tả</Label>
                      <Input placeholder={`VD: Thùng (24 lon)`} className="h-9 text-sm rounded-lg" />
                    </div>
                    <div className="space-y-1">
                      <Label className="text-xs">Giá Sỉ / {unit}</Label>
                      <Input placeholder="VD: 185.000" className="h-9 text-sm rounded-lg" />
                    </div>
                    <div className="space-y-1">
                      <Label className="text-xs">Giá Lẻ / {unit}</Label>
                      <Input placeholder="VD: 200.000" className="h-9 text-sm rounded-lg" />
                    </div>
                  </div>
                ))}
                <Button variant="outline" size="sm" className="h-8 text-xs rounded-lg">
                  <Plus className="w-3 h-3 mr-1" /> Thêm đơn vị khác
                </Button>
              </div>

              {/* Images */}
              <div className="border border-outline-variant rounded-xl p-4 space-y-3 bg-muted/10">
                <div className="flex justify-between items-center">
                  <p className="font-bold text-sm text-foreground">Ảnh sản phẩm</p>
                  <Button variant="outline" size="sm" className="h-8 text-xs rounded-lg">
                    <ImagePlus className="w-3.5 h-3.5 mr-1.5" /> Tải ảnh lên
                  </Button>
                </div>
                <p className="text-xs text-on-surface-variant">Tải nhiều ảnh. Nhấn ⭐ để đặt ảnh đại diện (Primary).</p>
                <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
                  {modalImages.map((img) => (
                    <div key={img.id} className={`relative group border-2 rounded-xl overflow-hidden aspect-square bg-white ${img.isPrimary ? "border-warning shadow-md" : "border-outline-variant"}`}>
                      <img src={img.url} alt="Ảnh sản phẩm" className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-1.5">
                        {!img.isPrimary && (
                          <Button variant="secondary" size="sm" className="h-7 text-[10px] font-bold" onClick={() => setPrimaryImage(img.id)}>
                            <Star className="w-2.5 h-2.5 mr-1" /> Đặt chính
                          </Button>
                        )}
                        <Button variant="destructive" size="icon" className="h-7 w-7">
                          <Trash2 className="w-3 h-3" />
                        </Button>
                      </div>
                      {img.isPrimary && (
                        <div className="absolute top-1.5 left-1.5 bg-warning text-warning-foreground text-[9px] font-bold px-1.5 py-0.5 rounded flex items-center">
                          <Star className="w-2.5 h-2.5 mr-0.5 fill-current" /> Chính
                        </div>
                      )}
                    </div>
                  ))}
                  <div className="border-2 border-dashed border-outline-variant rounded-xl aspect-square flex flex-col items-center justify-center text-on-surface-variant hover:bg-muted/50 cursor-pointer transition-colors">
                    <Plus className="w-6 h-6 mb-1 opacity-50" />
                    <span className="text-[10px] font-medium">Thêm ảnh</span>
                  </div>
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" className="mr-auto rounded-xl" onClick={() => setDialogOpen(false)}>Hủy</Button>
              <Button className="rounded-xl font-bold" onClick={handleSave}>Lưu sản phẩm</Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      {/* Category filter tabs */}
      <div className="flex gap-2 flex-wrap">
        {CATEGORIES.map((cat) => {
          const Icon = cat.icon;
          const active = categoryFilter === cat.group;
          const count = cat.group === "ALL" ? inventory.length : inventory.filter((p) => p.categoryGroup === cat.group).length;
          return (
            <button
              key={cat.group}
              onClick={() => setCategoryFilter(cat.group)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm border transition-all ${
                active
                  ? "bg-primary text-primary-foreground border-primary shadow-md"
                  : "bg-background border-outline-variant text-on-surface-variant hover:bg-muted"
              }`}
            >
              <Icon className="w-4 h-4" />
              {cat.key}
              <Badge className={`text-[10px] px-1.5 py-0 ml-0.5 ${active ? "bg-white/20 text-white" : "bg-muted text-muted-foreground"}`}>
                {count}
              </Badge>
            </button>
          );
        })}
      </div>

      {/* Search + actions */}
      <div className="bg-surface rounded-2xl border border-outline-variant shadow-sm p-4 flex flex-col sm:flex-row gap-4 items-center justify-between">
        <div className="relative w-full sm:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-outline w-4 h-4" />
          <Input
            placeholder="Tìm mã SP, tên sản phẩm, thương hiệu..."
            className="pl-10 bg-background border-outline-variant rounded-xl"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <Button variant="outline" className="flex items-center gap-2 bg-background border-outline-variant rounded-xl font-semibold">
            <Filter className="w-4 h-4" /> Lọc
          </Button>
          <Button variant="outline" className="flex items-center gap-2 bg-background border-outline-variant rounded-xl font-semibold">
            <Download className="w-4 h-4" /> Xuất CSV
          </Button>
        </div>
      </div>

      {/* Product cards */}
      <div className="space-y-3">
        {filtered.map((item) => {
          const expanded = expandedIds.has(item.id);
          const mainUnit = item.unitStocks[0];
          return (
            <div key={item.id} className="bg-background border border-outline-variant rounded-2xl overflow-hidden shadow-sm">
              {/* Row */}
              <div
                className="flex flex-wrap items-center gap-4 px-5 py-4 cursor-pointer hover:bg-muted/20 transition-colors select-none"
                onClick={() => toggleExpand(item.id)}
              >
                {/* Thumbnail */}
                <div className="w-14 h-14 rounded-xl border border-outline-variant/40 bg-white flex items-center justify-center shrink-0 overflow-hidden">
                  <img src={item.primaryImage} alt="" className="w-full h-full object-contain p-1" />
                </div>

                {/* Name + meta */}
                <div className="flex-grow min-w-0">
                  <p className="font-bold text-foreground line-clamp-1">{item.name}</p>
                  <div className="flex flex-wrap items-center gap-2 mt-1">
                    <Badge className="text-[10px] px-2 py-0 bg-muted text-on-surface-variant border-outline-variant/40 font-semibold">
                      {item.category}
                    </Badge>
                    <span className="text-xs text-on-surface-variant">{item.brand}</span>
                    <span className="text-xs text-on-surface-variant font-mono">{item.sku}</span>
                    <span className="text-xs text-on-surface-variant">
                      {item.unitStocks.length} đơn vị: {item.unitStocks.map((u) => u.unitType).join(" / ")}
                    </span>
                  </div>
                </div>

                {/* Stock + status + expand */}
                <div className="flex items-center gap-3 flex-wrap justify-end shrink-0">
                  <div className="text-right">
                    <p className="font-black text-lg text-foreground">{mainUnit.stock}</p>
                    <p className="text-xs text-on-surface-variant">{mainUnit.unitType}</p>
                  </div>
                  <Badge
                    variant="outline"
                    className={
                      item.status === "Còn hàng" ? "bg-success/15 text-success border-success/20" :
                      item.status === "Sắp hết"  ? "bg-warning/15 text-warning border-warning/20" :
                                                    "bg-destructive/15 text-destructive border-destructive/20"
                    }
                  >
                    {item.status === "Sắp hết" && <AlertTriangle className="w-3 h-3 mr-1" />}
                    {item.status}
                  </Badge>
                  <Button variant="ghost" size="sm" className="font-bold text-primary hover:bg-primary/10 rounded-xl"
                    onClick={(e) => { e.stopPropagation(); toast.success(`Đang sửa ${item.name}`); }}>
                    Sửa
                  </Button>
                  {expanded
                    ? <ChevronDown className="w-4 h-4 text-outline rotate-180 transition-transform" />
                    : <ChevronDown className="w-4 h-4 text-outline transition-transform" />}
                </div>
              </div>

              {/* Expanded: unit breakdown */}
              {expanded && (
                <div className="border-t border-outline-variant/30 px-5 py-4 bg-surface/40">
                  <p className="text-xs font-bold text-on-surface-variant uppercase tracking-widest mb-3">
                    Chi tiết tồn kho theo đơn vị hàng hóa
                  </p>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                    {item.unitStocks.map((u) => (
                      <div key={u.unitType} className="rounded-xl border border-outline-variant/40 bg-background p-4 space-y-2">
                        <div className="flex items-center justify-between">
                          <span className="font-bold text-sm text-foreground">{u.unitLabel}</span>
                          <Badge className="text-[10px] px-2 py-0 bg-primary/10 text-primary border-primary/20 font-bold capitalize">
                            {u.unitType}
                          </Badge>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-on-surface-variant">Tồn kho</span>
                          <span className="font-black text-foreground">{u.stock.toLocaleString()} {u.unitType}</span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-on-surface-variant">Giá Sỉ</span>
                          <span className="font-bold text-primary">{u.wholesalePrice}</span>
                        </div>
                        <div className="flex justify-between text-sm">
                          <span className="text-on-surface-variant">Giá Lẻ</span>
                          <span className="font-bold text-foreground">{u.retailPrice}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-16 bg-muted/20 rounded-2xl border border-dashed border-outline-variant">
          <Package2 className="w-16 h-16 mx-auto text-outline-variant opacity-20 mb-4" />
          <p className="text-xl font-bold text-on-surface-variant">Không có sản phẩm phù hợp</p>
        </div>
      )}
    </div>
  );
}

src/app/admin/locations/page.tsx.content:
"use client";

import { useMemo, useState } from "react";
import { GoogleMap, useLoadScript, Marker, InfoWindow } from "@react-google-maps/api";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";

// Ho Chi Minh City Coordinates
const center = {
  lat: 10.762622,
  lng: 106.660172
};

const stores = [
  { id: 1, name: "Tạp hóa Số 1", address: "Quận 1, HCM", lat: 10.776889, lng: 106.700806, status: "Active" },
  { id: 2, name: "Minimart Hoa Mai", address: "Quận 3, HCM", lat: 10.781846, lng: 106.685376, status: "Active" },
  { id: 3, name: "Đại lý Cấp 2 - Bình Tân", address: "Bình Tân, HCM", lat: 10.751334, lng: 106.602698, status: "Warning" },
  { id: 4, name: "Cửa hàng Tiện lợi 24h", address: "Quận 7, HCM", lat: 10.730301, lng: 106.711581, status: "Inactive" },
];

export default function StoreLocationsPage() {
  // To make the map work in a real environment, replace "YOUR_GOOGLE_MAPS_API_KEY"
  // with a valid key from Google Cloud Console.
  const { isLoaded } = useLoadScript({
    googleMapsApiKey: process.env.NEXT_PUBLIC_GOOGLE_MAPS_API_KEY || "YOUR_GOOGLE_MAPS_API_KEY",
  });

  const [selectedStore, setSelectedStore] = useState<typeof stores[0] | null>(null);

  const mapOptions = useMemo(() => ({
    disableDefaultUI: false,
    clickableIcons: true,
    scrollwheel: true,
  }), []);

  if (!isLoaded) {
    return (
      <div className="space-y-6">
        <h1 className="text-3xl font-bold">Store Locations</h1>
        <Skeleton className="w-full h-[600px] rounded-xl" />
      </div>
    );
  }

  return (
    <div className="space-y-6 flex flex-col h-full min-h-[80vh]">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Store Locations</h1>
          <p className="text-muted-foreground">Geographical distribution of all registered B2B dealers.</p>
        </div>
        <div className="flex gap-2">
          <Badge className="bg-success text-success-foreground hover:bg-success">Active: 2</Badge>
          <Badge className="bg-warning text-warning-foreground hover:bg-warning">Warning: 1</Badge>
          <Badge className="bg-destructive text-destructive-foreground hover:bg-destructive">Inactive: 1</Badge>
        </div>
      </div>

      <Card className="flex-grow border-border shadow-md overflow-hidden relative">
        <CardContent className="p-0 h-[600px] w-full relative">
          {/* Note: Map might show "Development purposes only" if API Key is invalid */}
          <GoogleMap
            zoom={12}
            center={center}
            mapContainerClassName="w-full h-full"
            options={mapOptions}
          >
            {stores.map((store) => (
              <Marker
                key={store.id}
                position={{ lat: store.lat, lng: store.lng }}
                onClick={() => setSelectedStore(store)}
                icon={{
                  url: store.status === 'Active' 
                    ? 'http://maps.google.com/mapfiles/ms/icons/green-dot.png'
                    : store.status === 'Warning'
                    ? 'http://maps.google.com/mapfiles/ms/icons/yellow-dot.png'
                    : 'http://maps.google.com/mapfiles/ms/icons/red-dot.png'
                }}
              />
            ))}

            {selectedStore && (
              <InfoWindow
                position={{ lat: selectedStore.lat, lng: selectedStore.lng }}
                onCloseClick={() => setSelectedStore(null)}
              >
                <div className="p-2 space-y-2 min-w-[200px] text-foreground">
                  <h3 className="font-bold text-lg">{selectedStore.name}</h3>
                  <p className="text-sm text-muted-foreground">{selectedStore.address}</p>
                  <Badge 
                    className={
                      selectedStore.status === 'Active' ? 'bg-success text-white' :
                      selectedStore.status === 'Warning' ? 'bg-warning text-white' :
                      'bg-destructive text-white'
                    }
                  >
                    {selectedStore.status}
                  </Badge>
                </div>
              </InfoWindow>
            )}
          </GoogleMap>

          <div className="absolute top-4 left-4 bg-background/90 backdrop-blur-md p-4 rounded-lg shadow-lg border border-border w-64">
            <h4 className="font-bold mb-2">Location Status</h4>
            <div className="space-y-2 text-sm">
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-success"></div> Active (Healthy)</span>
                <span className="font-bold">2</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-warning"></div> Low Activity</span>
                <span className="font-bold">1</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-destructive"></div> Inactive</span>
                <span className="font-bold">1</span>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

src/app/admin/orders/page.tsx.content:
"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
  Search, CalendarDays, Filter, CheckCircle2, Truck, Clock,
  AlertCircle, ChevronDown, ChevronUp, Box, Package2,
  Store, Banknote,
} from "lucide-react";
import { toast } from "sonner";
import { useState } from "react";
import products from "@/data/products.json";

type OrderStatus = "PENDING" | "SHIPPING" | "PAID_AND_DELIVERED";

type OrderItem = {
  productId: string;
  qty: number;
  unitType: string;
  unitLabel: string;
  purchaseType: "si" | "le";
  price: string;
};

type Order = {
  id: string;
  store: string;
  address: string;
  date: string;
  total: string;
  status: OrderStatus;
  items: OrderItem[];
};

const INITIAL_ORDERS: Order[] = [
  {
    id: "ORD-0899",
    store: "Tạp hóa Số 1",
    address: "Tạp hóa Số 1, Quận 1, TP.HCM",
    date: "05/05/2026 14:30",
    total: "1.975.000đ",
    status: "PENDING",
    items: [
      { productId: "PROD-001", qty: 5,  unitType: "thùng", unitLabel: "Thùng (24 lon)",  purchaseType: "si", price: "925.000đ" },
      { productId: "PROD-002", qty: 10, unitType: "thùng", unitLabel: "Thùng (30 gói)", purchaseType: "si", price: "1.050.000đ" },
    ],
  },
  {
    id: "ORD-0898",
    store: "Minimart Hoa Mai",
    address: "128 Nguyễn Thị Minh Khai, Quận 3, TP.HCM",
    date: "05/05/2026 10:15",
    total: "4.500.000đ",
    status: "SHIPPING",
    items: [
      { productId: "PROD-003", qty: 12, unitType: "lốc",   unitLabel: "Lốc (4 hộp)",    purchaseType: "si", price: "3.420.000đ" },
      { productId: "PROD-004", qty: 2,  unitType: "can",   unitLabel: "Can (5 lít)",      purchaseType: "si", price: "1.080.000đ" },
    ],
  },
  {
    id: "ORD-0897",
    store: "Đại lý Cấp 2 - Bình Tân",
    address: "Đại lý Cấp 2 - Bình Tân, TP.HCM",
    date: "04/05/2026 16:45",
    total: "12.000.000đ",
    status: "PAID_AND_DELIVERED",
    items: [
      { productId: "PROD-001", qty: 20, unitType: "thùng", unitLabel: "Thùng (24 lon)",  purchaseType: "si", price: "3.700.000đ" },
      { productId: "PROD-002", qty: 40, unitType: "thùng", unitLabel: "Thùng (30 gói)", purchaseType: "si", price: "4.400.000đ" },
      { productId: "PROD-004", qty: 7,  unitType: "thùng", unitLabel: "Thùng (12 chai)", purchaseType: "si", price: "3.900.000đ" },
    ],
  },
];

const STATUS_FILTERS = [
  { key: "ALL",                label: "Tất cả" },
  { key: "PENDING",            label: "Chờ xử lý" },
  { key: "SHIPPING",           label: "Đang giao" },
  { key: "PAID_AND_DELIVERED", label: "Đã hoàn tất" },
] as const;

export default function AdminOrdersPage() {
  const [orders, setOrders] = useState<Order[]>(INITIAL_ORDERS);
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set(["ORD-0899"]));
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState<"ALL" | OrderStatus>("ALL");

  const toggleExpand = (id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const handleConfirm = (orderId: string) => {
    toast.promise(
      new Promise<void>((resolve) => setTimeout(resolve, 1000)),
      {
        loading: `Đang xử lý thanh toán & trừ kho cho ${orderId}...`,
        success: () => {
          setOrders((prev) =>
            prev.map((o) => o.id === orderId ? { ...o, status: "PAID_AND_DELIVERED" } : o)
          );
          return `${orderId} đã xác nhận. Kho trừ tự động!`;
        },
        error: "Lỗi kết nối cơ sở dữ liệu",
      }
    );
  };

  const handleShipping = (orderId: string) => {
    toast.promise(
      new Promise<void>((resolve) => setTimeout(resolve, 800)),
      {
        loading: `Đang cập nhật trạng thái giao hàng ${orderId}...`,
        success: () => {
          setOrders((prev) =>
            prev.map((o) => o.id === orderId ? { ...o, status: "SHIPPING" } : o)
          );
          return `${orderId} đã chuyển sang Đang giao!`;
        },
        error: "Lỗi cập nhật trạng thái",
      }
    );
  };

  const getStatusBadge = (status: OrderStatus) => {
    switch (status) {
      case "PENDING":
        return <Badge className="bg-warning/15 text-warning border-warning/20 px-3 py-1 font-bold"><Clock className="w-3.5 h-3.5 mr-1.5" />Chờ xử lý</Badge>;
      case "SHIPPING":
        return <Badge className="bg-primary/15 text-primary border-primary/20 px-3 py-1 font-bold"><Truck className="w-3.5 h-3.5 mr-1.5" />Đang giao</Badge>;
      case "PAID_AND_DELIVERED":
        return <Badge className="bg-success/15 text-success border-success/20 px-3 py-1 font-bold"><CheckCircle2 className="w-3.5 h-3.5 mr-1.5" />Đã giao &amp; Thu tiền</Badge>;
    }
  };

  const filtered = orders.filter((o) => {
    const matchStatus = statusFilter === "ALL" || o.status === statusFilter;
    const q = searchTerm.toLowerCase().trim();
    const matchSearch = !q || o.id.toLowerCase().includes(q) || o.store.toLowerCase().includes(q);
    return matchStatus && matchSearch;
  });

  const counts = {
    ALL: orders.length,
    PENDING: orders.filter((o) => o.status === "PENDING").length,
    SHIPPING: orders.filter((o) => o.status === "SHIPPING").length,
    PAID_AND_DELIVERED: orders.filter((o) => o.status === "PAID_AND_DELIVERED").length,
  };

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-4xl font-extrabold text-foreground tracking-tight">Quản lý Đơn hàng</h1>
          <p className="text-lg text-on-surface-variant font-medium mt-1">Xác nhận giao hàng, thu tiền COD và trừ kho theo từng mặt hàng</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
        {STATUS_FILTERS.map((f) => (
          <button
            key={f.key}
            onClick={() => setStatusFilter(f.key)}
            className={`rounded-2xl p-4 text-left border transition-all ${
              statusFilter === f.key
                ? "bg-primary text-primary-foreground border-primary shadow-md"
                : "bg-surface border-outline-variant hover:bg-muted"
            }`}
          >
            <p className={`text-3xl font-black ${statusFilter === f.key ? "text-primary-foreground" : "text-foreground"}`}>
              {counts[f.key]}
            </p>
            <p className={`text-sm font-semibold mt-1 ${statusFilter === f.key ? "text-primary-foreground/80" : "text-on-surface-variant"}`}>
              {f.label}
            </p>
          </button>
        ))}
      </div>

      {/* Search + Filter Bar */}
      <div className="bg-surface rounded-2xl border border-outline-variant shadow-sm p-5 flex flex-col lg:flex-row gap-4 items-center justify-between">
        <div className="relative w-full lg:w-[500px]">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-outline w-5 h-5" />
          <Input
            placeholder="Tìm mã đơn, tên đại lý / cửa hàng..."
            className="pl-12 py-6 text-base bg-background border-outline-variant rounded-xl focus:ring-primary/20"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex gap-3 w-full lg:w-auto">
          <Button variant="outline" className="flex items-center gap-2 bg-background border-outline-variant font-bold px-6 h-12 rounded-xl hover:bg-muted">
            <CalendarDays className="w-5 h-5" /> Hôm nay
          </Button>
          <Button variant="outline" className="flex items-center gap-2 bg-background border-outline-variant font-bold px-6 h-12 rounded-xl hover:bg-muted">
            <Filter className="w-5 h-5" /> Lọc nâng cao
          </Button>
        </div>
      </div>

      {/* Order Cards */}
      <div className="space-y-4">
        {filtered.map((order) => {
          const expanded = expandedIds.has(order.id);
          return (
            <div key={order.id} className="bg-background rounded-2xl border border-outline-variant shadow-sm overflow-hidden">

              {/* Row header */}
              <div
                className={`flex flex-wrap items-center gap-3 px-6 py-4 cursor-pointer select-none transition-colors ${
                  order.status === "PENDING" ? "bg-warning/5 hover:bg-warning/10"
                  : order.status === "SHIPPING" ? "bg-primary/5 hover:bg-primary/10"
                  : "bg-success/5 hover:bg-success/10"
                }`}
                onClick={() => toggleExpand(order.id)}
              >
                {/* Order ID + store */}
                <div className="flex items-center gap-3 flex-grow min-w-0">
                  <span className="font-black text-lg text-primary shrink-0">{order.id}</span>
                  <div className="flex items-center gap-1.5 text-on-surface-variant font-medium text-sm min-w-0">
                    <Store className="w-4 h-4 shrink-0" />
                    <span className="truncate">{order.store}</span>
                  </div>
                </div>

                {/* Right: date, total, status, expand */}
                <div className="flex items-center gap-3 flex-wrap justify-end">
                  <span className="text-sm text-on-surface-variant font-medium">{order.date}</span>
                  <span className="font-black text-lg text-foreground">{order.total}</span>
                  {getStatusBadge(order.status)}
                  {expanded
                    ? <ChevronUp className="w-5 h-5 text-outline shrink-0" />
                    : <ChevronDown className="w-5 h-5 text-outline shrink-0" />}
                </div>
              </div>

              {/* Expanded: item details */}
              {expanded && (
                <div className="px-6 py-5 space-y-4 border-t border-outline-variant/30">

                  {/* Address */}
                  <div className="flex items-center gap-2 text-sm text-on-surface-variant bg-muted/30 rounded-xl px-4 py-2.5">
                    <Package2 className="w-4 h-4 text-primary shrink-0" />
                    <span className="font-medium">{order.address}</span>
                  </div>

                  {/* Items */}
                  <div>
                    <p className="text-xs font-bold text-on-surface-variant uppercase tracking-widest mb-3">Chi tiết hàng hóa ({order.items.length} mặt hàng)</p>
                    <div className="space-y-2">
                      {order.items.map((item, idx) => {
                        const product = products.find((p) => p.id === item.productId);
                        return (
                          <div key={idx} className="flex items-center gap-4 rounded-xl border border-outline-variant/30 bg-surface/60 px-4 py-3">
                            {/* Thumbnail */}
                            <div className="w-12 h-12 rounded-lg border border-outline-variant/40 bg-white flex items-center justify-center shrink-0 overflow-hidden">
                              {product?.primaryImage
                                ? <img src={product.primaryImage} alt="" className="w-full h-full object-contain p-1" />
                                : <Box className="w-6 h-6 text-outline-variant" />}
                            </div>

                            {/* Product info */}
                            <div className="flex-grow min-w-0">
                              <p className="font-bold text-sm text-foreground line-clamp-1">{product?.name ?? item.productId}</p>
                              <div className="flex flex-wrap items-center gap-1.5 mt-1">
                                <Badge className="text-[10px] px-1.5 py-0 bg-muted text-on-surface-variant border-outline-variant/40 font-semibold">
                                  {product?.category ?? "—"}
                                </Badge>
                                <span className="text-xs text-on-surface-variant font-medium">{item.unitLabel}</span>
                                {item.purchaseType === "si"
                                  ? <Badge className="text-[10px] px-1.5 py-0 bg-primary/10 text-primary border-primary/20 font-bold">Sỉ</Badge>
                                  : <Badge className="text-[10px] px-1.5 py-0 bg-secondary/10 text-secondary border-secondary/20 font-bold">Lẻ</Badge>}
                              </div>
                            </div>

                            {/* Qty + price */}
                            <div className="text-right shrink-0">
                              <p className="font-black text-primary text-base">{item.price}</p>
                              <p className="text-xs text-on-surface-variant mt-0.5">× {item.qty} {item.unitType}</p>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Action buttons */}
                  <div className="flex flex-wrap gap-3 justify-end pt-2 border-t border-outline-variant/20">
                    {order.status === "PENDING" && (
                      <Button
                        className="bg-primary hover:bg-primary/90 text-white font-bold rounded-xl px-6 shadow"
                        onClick={() => handleShipping(order.id)}
                      >
                        <Truck className="w-4 h-4 mr-2" />
                        Bắt đầu Giao hàng
                      </Button>
                    )}
                    {order.status === "SHIPPING" && (
                      <Button
                        className="bg-success hover:bg-success/90 text-white font-bold rounded-xl px-6 shadow"
                        onClick={() => handleConfirm(order.id)}
                      >
                        <Banknote className="w-4 h-4 mr-2" />
                        Xác nhận Đã Giao & Thu tiền
                      </Button>
                    )}
                    {order.status === "PAID_AND_DELIVERED" && (
                      <div className="flex items-center gap-2 text-success font-bold text-sm bg-success/5 py-2 px-4 rounded-xl border border-success/20">
                        <CheckCircle2 className="w-4 h-4" /> Đã hoàn tất – Kho đã trừ
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-16 bg-muted/20 rounded-2xl border border-dashed border-outline-variant">
          <Package2 className="w-16 h-16 mx-auto text-outline-variant opacity-20 mb-4" />
          <p className="text-xl font-bold text-on-surface-variant">Không có đơn hàng phù hợp</p>
        </div>
      )}

      {/* Info note */}
      <div className="bg-primary/5 rounded-2xl p-6 border border-primary/20 flex gap-4 items-start">
        <AlertCircle className="w-6 h-6 text-primary shrink-0 mt-0.5" />
        <div className="space-y-1">
          <p className="text-lg font-bold text-foreground">Lưu ý quan trọng:</p>
          <p className="text-on-surface-variant leading-relaxed text-sm">
            Tồn kho chỉ được trừ sau khi nhấn <span className="font-bold text-primary">&ldquo;Xác nhận Đã Giao &amp; Thu tiền&rdquo;</span>.
            Quy trình: <span className="font-semibold">Chờ xử lý → Đang giao → Đã giao & Thu tiền</span>. Mỗi bước trừ kho theo đúng đơn vị (thùng / can / chai / lốc / gói).
          </p>
        </div>
      </div>
    </div>
  );
}

src/app/api/graphify/route.ts.content:
import { NextResponse } from "next/server";
import graphData from "../../../../.graphify/graph.json";
import contextData from "../../../../.graphify/context.json";
import type { GraphData, ContextData } from "@/lib/graphify-context";

export async function GET() {
  try {
    const payload = {
      graph: graphData as unknown as GraphData,
      context: contextData as unknown as ContextData,
    };
    return NextResponse.json(payload);
  } catch (e) {
    return NextResponse.json(
      { error: e instanceof Error ? e.message : "Failed to load graphify data" },
      { status: 500 }
    );
  }
}

