"use client";

import { useMemo, useCallback, useRef } from "react";
import dynamic from "next/dynamic";
import * as THREE from "three";
import type { GraphData, GraphNode } from "@/lib/graphify-context";
import { nodeColorByCommunity } from "@/lib/graphify-context";

const ForceGraph3D = dynamic(() => import("react-force-graph-3d"), { ssr: false });

interface Props {
  graph: GraphData;
  selectedNode: GraphNode | null;
  onNodeClick: (node: GraphNode) => void;
  onBackgroundClick?: () => void;
  hiddenNodes?: Set<string>;
  linkedNodes?: Map<string, number>;
}

function createLabelSprite(
  text: string,
  color: string,
  fontSize = 28,
  opacity = 1,
) {
  const canvas = document.createElement("canvas");
  const ctx = canvas.getContext("2d")!;
  ctx.font = `bold ${fontSize}px ui-sans-serif, system-ui, sans-serif`;
  const metrics = ctx.measureText(text);
  const w = Math.max(128, Math.ceil(metrics.width) + 24);
  const h = fontSize + 16;
  canvas.width = w;
  canvas.height = h;

  ctx.fillStyle = `rgba(9,9,11,${0.6 * opacity})`;
  ctx.fillRect(0, 0, w, h);

  ctx.fillStyle = color;
  ctx.font = `bold ${fontSize}px ui-sans-serif, system-ui, sans-serif`;
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.fillText(text, w / 2, h / 2);

  const texture = new THREE.CanvasTexture(canvas);
  const material = new THREE.SpriteMaterial({
    map: texture,
    transparent: true,
    depthTest: false,
    opacity,
  });
  const sprite = new THREE.Sprite(material);
  sprite.scale.set(w / 16, h / 16, 1);
  sprite.position.y = 2.2;
  return sprite;
}

export default function GraphifyForceGraph3D({
  graph,
  selectedNode,
  onNodeClick,
  onBackgroundClick,
  hiddenNodes,
  linkedNodes,
}: Props) {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const fgRef = useRef<any>(null);
  /* Degree map for sizing */
  const degreeMap = useMemo(() => {
    const d = new Map<string, number>();
    for (const l of graph.links) {
      d.set(l.source, (d.get(l.source) ?? 0) + 1);
      d.set(l.target, (d.get(l.target) ?? 0) + 1);
    }
    return d;
  }, [graph.links]);

  const fgData = useMemo(() => {
    const nodes = graph.nodes
      .filter((n) => !hiddenNodes?.has(n.id))
      .map((n) => {
        const isSelected = n.id === selectedNode?.id;
        const isLinked = linkedNodes?.has(n.id);
        const degree = degreeMap.get(n.id) ?? 0;
        return {
          ...n,
          color: nodeColorByCommunity(n.community),
          val: isSelected ? 10 : isLinked ? 7 : Math.max(3, Math.min(8, 2 + degree * 0.5)),
          __degree: degree,
          __isSelected: isSelected,
          __isLinked: isLinked,
        };
      });

    const nodeIds = new Set(nodes.map((n) => n.id));
    const relatedIds = selectedNode ? new Set([selectedNode.id, ...(linkedNodes?.keys() ?? [])]) : null;
    const links = graph.links
      .filter((l) => nodeIds.has(l.source) && nodeIds.has(l.target))
      .map((l) => ({ ...l, __isRelated: relatedIds ? relatedIds.has(l.source) && relatedIds.has(l.target) : false }));

    return { nodes, links };
  }, [graph, hiddenNodes, selectedNode, linkedNodes, degreeMap]);

  const handleNodeClick = useCallback(
    (node: unknown) => {
      const n = node as GraphNode & { x?: number; y?: number; z?: number };
      onNodeClick(n);
      if (fgRef.current && typeof fgRef.current.cameraPosition === "function" && n.x != null) {
        const dist = 140;
        const ratio = 1 + dist / Math.hypot(n.x, n.y || 0, n.z || 0);
        fgRef.current.cameraPosition(
          { x: n.x * ratio, y: (n.y || 0) * ratio, z: (n.z || 0) * ratio },
          { x: n.x, y: n.y || 0, z: n.z || 0 },
          1200
        );
      }
    },
    [onNodeClick]
  );

  return (
    <div className="w-full h-full bg-zinc-950 rounded-lg overflow-hidden relative">
      <ForceGraph3D
        ref={fgRef}
        graphData={fgData}
        backgroundColor="#09090b"
        nodeLabel={(n: unknown) => (n as GraphNode).label}
        onNodeClick={handleNodeClick}
        onBackgroundClick={onBackgroundClick}
        linkColor={(l: unknown) => (l as { __isRelated?: boolean }).__isRelated ? "rgba(245,158,11,0.55)" : "rgba(255,255,255,0.04)"}
        linkDirectionalArrowLength={3}
        linkDirectionalArrowColor={(l: unknown) => (l as { __isRelated?: boolean }).__isRelated ? "rgba(245,158,11,0.6)" : "rgba(255,255,255,0.06)"}
        linkDirectionalParticles={(l: unknown) => (l as { __isRelated?: boolean }).__isRelated ? 4 : 0}
        linkDirectionalParticleWidth={1}
        linkDirectionalParticleSpeed={0.008}
        nodeColor={(n: unknown) => {
          const node = n as GraphNode;
          if (node.id === selectedNode?.id) return "#ffffff";
          if (linkedNodes?.has(node.id)) return "#f59e0b";
          return nodeColorByCommunity(node.community);
        }}
        nodeRelSize={6}
        nodeResolution={16}
        linkWidth={(l: unknown) => (l as { __isRelated?: boolean }).__isRelated ? 2 : 0.3}
        warmupTicks={60}
        cooldownTicks={80}
        nodeThreeObject={(n: unknown) => {
          const node = n as GraphNode & { __degree: number; __isSelected: boolean; __isLinked: boolean; color: string; val: number };
          const group = new THREE.Group();

          /* Sphere */
          const geo = new THREE.SphereGeometry(1, 16, 16);
          const mat = new THREE.MeshLambertMaterial({
            color: node.id === selectedNode?.id ? 0xffffff : linkedNodes?.has(node.id) ? 0xf59e0b : node.color,
            transparent: true,
            opacity: selectedNode && !node.__isSelected && !node.__isLinked ? 0.15 : 0.92,
          });
          const mesh = new THREE.Mesh(geo, mat);
          mesh.scale.setScalar(node.val / 3);
          group.add(mesh);

          /* Label for every node — bigger/brighter for selected/linked */
          const labelColor = node.__isSelected
            ? "#ffffff"
            : node.__isLinked
              ? "#fbbf24"
              : "#a1a1aa";
          const fontSize = node.__isSelected ? 32 : node.__isLinked ? 28 : 20;
          const opacity = node.__isSelected ? 1 : node.__isLinked ? 0.9 : selectedNode ? 0.25 : 0.65;
          const sprite = createLabelSprite(node.label, labelColor, fontSize, opacity);
          group.add(sprite);

          /* Selection glow ring */
          if (node.__isSelected) {
            const ringGeo = new THREE.RingGeometry(1.4, 1.6, 32);
            const ringMat = new THREE.MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 0.3, side: THREE.DoubleSide });
            const ring = new THREE.Mesh(ringGeo, ringMat);
            ring.scale.setScalar(node.val / 3);
            ring.lookAt(new THREE.Vector3(0, 0, 1));
            group.add(ring);
          }

          return group;
        }}
      />
    </div>
  );
}

src/components/shared/header.tsx.content:
"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { useEffect, useMemo, useState } from "react";
import { 
  Store, 
  ShoppingCart, 
  Package, 
  Headphones, 
  Box,
  ShieldCheck,
  Bell,
  UserCircle,
  ChevronDown,
  LogOut,
  User,
} from "lucide-react";
import { ThemeToggle } from "./theme-toggle";
import { TextSizeToggle } from "./text-size-toggle";
import { Separator } from "@/components/ui/separator";
import { Button } from "@/components/ui/button";
import { Heading, Text } from "./typography";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

type MockSession = {
  id: string;
  username: string;
  role: "admin" | "store";
  displayName: string;
};

export function Header() {
  const pathname = usePathname();
  const router = useRouter();
  const [session, setSession] = useState<MockSession | null>(null);

  useEffect(() => {
    const raw = localStorage.getItem("storesync_session");
    if (!raw) {
      setSession(null);
      return;
    }
    try {
      setSession(JSON.parse(raw));
    } catch {
      setSession(null);
    }
  }, [pathname]);

  const nav = useMemo(() => {
    if (session?.role === "admin") {
      return [
        { href: "/admin/orders", label: "Quản lý đơn", icon: Package },
        { href: "/admin/inventory", label: "Kho hàng", icon: ShoppingCart },
        { href: "/admin/locations", label: "Đại lý", icon: Headphones },
        { href: "/graph", label: "Sơ đồ hệ thống", icon: Box },
      ];
    }
    return [
      { href: "/catalog", label: "Danh mục sỉ", icon: ShoppingCart },
      { href: "/orders", label: "Đơn hàng", icon: Package },
      { href: "/support", label: "Hỗ trợ", icon: Headphones },
      { href: "/graph", label: "Sơ đồ hệ thống", icon: Box },
    ];
  }, [session?.role]);

  const profileHref = "/profile";

  const handleLogout = () => {
    localStorage.removeItem("storesync_session");
    setSession(null);
    router.push("/login");
  };

  return (
    <header className="sticky top-0 z-50 w-full border-b border-outline-variant bg-surface/80 backdrop-blur shadow-sm">
      <div className="mx-auto flex h-16 max-w-full items-center px-lg">
        {/* Brand */}
        <Link href="/" className="flex items-center gap-sm group">
          <div className="bg-primary/10 p-1.5 rounded-lg transition-colors group-hover:bg-primary/20">
            <Store className="size-6 text-primary" />
          </div>
          <Heading as="span" size="title" className="text-primary tracking-tight">StoreSync B2B</Heading>
        </Link>

        {/* Nav */}
        <nav className="ml-auto hidden md:flex items-center gap-md text-label-md">
          {nav.map((item) => {
            const isActive = pathname === item.href;
            return (
              <Link
                key={item.href}
                href={item.href}
                className={
                  "relative flex items-center gap-1.5 px-1 py-1 transition-all duration-200 " +
                  (isActive
                    ? "text-primary font-semibold"
                    : "text-on-surface-variant hover:text-primary")
                }
              >
                <Text as="span" variant="label" className="font-bold">{item.label}</Text>
                {isActive && (
                  <span className="absolute -bottom-[21px] left-0 right-0 h-0.5 bg-primary rounded-full" />
                )}
              </Link>
            );
          })}

          <Separator orientation="vertical" className="mx-2 h-6 bg-outline-variant/50" />

          <div className="flex items-center gap-1">
            <Button variant="ghost" size="icon" className="text-on-surface-variant hover:text-primary">
              <Bell className="size-5" />
            </Button>
            {session ? (
              <DropdownMenu>
                <DropdownMenuTrigger
                  className="flex items-center gap-2 rounded-lg px-2 py-1.5 hover:bg-muted transition-colors"
                >
                  {session.role === "admin" ? (
                    <ShieldCheck className="size-5 text-primary" />
                  ) : (
                    <UserCircle className="size-5 text-primary" />
                  )}
                  <span className="text-xs font-semibold text-foreground max-w-28 truncate">
                    {session.displayName}
                  </span>
                  <ChevronDown className="size-3.5 text-muted-foreground" />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-56">
                  <DropdownMenuGroup>
                    <DropdownMenuLabel>Tài khoản</DropdownMenuLabel>
                    <DropdownMenuItem onClick={() => router.push(profileHref)}>
                      <User className="size-4" />
                      Trang cá nhân
                    </DropdownMenuItem>
                    <DropdownMenuItem onClick={() => router.push(session.role === "admin" ? "/admin/orders" : "/dashboard")}>
                      <Package className="size-4" />
                      Khu vực làm việc
                    </DropdownMenuItem>
                  </DropdownMenuGroup>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem variant="destructive" onClick={handleLogout}>
                    <LogOut className="size-4" />
                    Đăng xuất
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            ) : (
              <Link href="/login">
                <Button variant="ghost" size="icon" className="text-on-surface-variant hover:text-primary">
                  <UserCircle className="size-5" />
                </Button>
              </Link>
            )}
          </div>

          <Separator orientation="vertical" className="mx-2 h-6 bg-outline-variant/50" />

          <div className="flex items-center gap-2">
            <TextSizeToggle />
            <ThemeToggle />
          </div>
        </nav>
      </div>
    </header>
  );
}

src/components/shared/layout.tsx.content:
import { cn } from "@/lib/utils";

// ── Page shell ───────────────────────────────────────────────
export function Page({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <main className={cn("flex flex-col min-h-screen", className)}>
      {children}
    </main>
  );
}

export function PageContent({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "flex-1 flex flex-col p-6 md:p-16 space-y-12",
        className,
      )}
    >
      {children}
    </div>
  );
}

export function PageSection({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <section className={cn("w-full mx-auto max-w-7xl", className)}>{children}</section>
  );
}

// ── Hero block ───────────────────────────────────────────────
export function Hero({
  children,
  className,
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div className={cn("text-center space-y-5 max-w-4xl mx-auto w-full", className)}>
      {children}
    </div>
  );
}

// ── Container (max-width) ───────────────────────────────────
export function Container({
  children,
  className,
  max = "7xl",
}: {
  children: React.ReactNode;
  className?: string;
  max?:
  | "sm"
  | "md"
  | "lg"
  | "xl"
  | "2xl"
  | "3xl"
  | "4xl"
  | "5xl"
  | "6xl"
  | "7xl"
  | "8xl"
  | "full";
}) {
  const widths: Record<string, string> = {
    sm: "max-w-sm",
    md: "max-w-md",
    lg: "max-w-lg",
    xl: "max-w-xl",
    "2xl": "max-w-2xl",
    "3xl": "max-w-3xl",
    "4xl": "max-w-4xl",
    "5xl": "max-w-5xl",
    "6xl": "max-w-6xl",
    "7xl": "max-w-7xl",
    "8xl": "max-w-[1440px]",
    full: "max-w-full",
  };
  return (
    <div className={cn("w-full mx-auto", widths[max], className)}>
      {children}
    </div>
  );
}

// ── Stack (flex gap) ────────────────────────────────────────
interface StackProps extends React.HTMLAttributes<HTMLDivElement> {
  direction?: "row" | "col";
  gap?: 0 | 1 | 2 | 3 | 4 | 5 | 6 | 8 | 10 | 12;
  align?: "start" | "center" | "end" | "stretch";
  justify?: "start" | "center" | "end" | "between";
  wrap?: boolean;
}

export function Stack({
  direction = "col",
  gap = 4,
  align,
  justify,
  wrap,
  className,
  children,
  ...props
}: StackProps) {
  return (
    <div
      className={cn(
        "flex",
        direction === "row" ? "flex-row" : "flex-col",
        `gap-${gap}`,
        align &&
        {
          start: "items-start",
          center: "items-center",
          end: "items-end",
          stretch: "items-stretch",
        }[align],
        justify &&
        {
          start: "justify-start",
          center: "justify-center",
          end: "justify-end",
          between: "justify-between",
        }[justify],
        wrap && "flex-wrap",
        className,
      )}
      {...props}
    >
      {children}
    </div>
  );
}

// ── Grid ───────────────────────────────────────────────────
interface GridProps extends React.HTMLAttributes<HTMLDivElement> {
  cols?: 1 | 2 | 3 | 4 | 5 | 6;
  gap?: 0 | 1 | 2 | 3 | 4 | 5 | 6 | 8;
}

export function Grid({
  cols = 1,
  gap = 4,
  className,
  children,
  ...props
}: GridProps) {
  const colsClass: Record<number, string> = {
    1: "grid-cols-1",
    2: "grid-cols-1 md:grid-cols-2",
    3: "grid-cols-1 md:grid-cols-2 lg:grid-cols-3",
    4: "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4",
    5: "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5",
    6: "grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-6",
  };
  return (
    <div
      className={cn("grid", colsClass[cols], `gap-${gap}`, className)}
      {...props}
    >
      {children}
    </div>
  );
}

// ── Section divider ──────────────────────────────────────────
export function Divider({
  label,
  className,
}: {
  label?: string;
  className?: string;
}) {
  return (
    <div className={cn("flex items-center gap-3", className)}>
      <div className="h-px flex-1 bg-border" />
      {label && (
        <span className="text-caption font-medium text-muted-foreground uppercase tracking-wider">
          {label}
        </span>
      )}
      <div className="h-px flex-1 bg-border" />
    </div>
  );
}

