import { useCallback, useMemo, useSyncExternalStore, useState } from "react";
import { Todo } from "@/types/todo";
import { generateId } from "@/lib/utils";
import { StorageLib } from "@/lib/storage";

const STORAGE_KEY = "demo_todos_state";

export type TodoFilter = "all" | "active" | "completed";

export interface TodoStats {
  total: number;
  completed: number;
  active: number;
}

/* External store for SSR-safe localStorage subscription */
let lastRaw: string | null = null;
let lastParsed: Todo[] = [];

function getClientSnapshot(): Todo[] {
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (raw === lastRaw) return lastParsed;
    lastRaw = raw;
    lastParsed = raw ? (JSON.parse(raw) as Todo[]) : [];
    return lastParsed;
  } catch {
    return lastParsed;
  }
}

function subscribe(callback: () => void) {
  const handler = () => {
    // invalidate cache so next getClientSnapshot re-reads
    lastRaw = null;
    callback();
  };
  window.addEventListener("storage", handler);
  return () => window.removeEventListener("storage", handler);
}

function notify() {
  // invalidate cache before dispatching so subscribers pick up new data
  lastRaw = null;
  window.dispatchEvent(new StorageEvent("storage"));
}

export function useTodos(initialTodos: Todo[] = []) {
  const storeTodos = useSyncExternalStore(
    subscribe,
    getClientSnapshot,
    () => initialTodos
  );

  /* Filter is local UI state, not persisted */
  const [filter, setFilter] = useState<TodoFilter>("all");

  const setTodos = useCallback((updater: (prev: Todo[]) => Todo[]) => {
    const current = StorageLib.get<Todo[]>(STORAGE_KEY, []);
    const next = updater(current);
    StorageLib.set(STORAGE_KEY, next);
    notify();
  }, []);

  const addTodo = useCallback((title: string) => {
    const trimmed = title.trim();
    if (!trimmed) return;
    const newTodo: Todo = {
      id: generateId(),
      title: trimmed,
      completed: false,
      createdAt: Date.now(),
    };
    setTodos((prev) => [newTodo, ...prev]);
  }, [setTodos]);

  const toggleTodo = useCallback((id: string) => {
    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id ? { ...todo, completed: !todo.completed } : todo
      )
    );
  }, [setTodos]);

  const removeTodo = useCallback((id: string) => {
    setTodos((prev) => prev.filter((todo) => todo.id !== id));
  }, [setTodos]);

  const editTodo = useCallback((id: string, newTitle: string) => {
    const trimmed = newTitle.trim();
    if (!trimmed) return;
    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id ? { ...todo, title: trimmed } : todo
      )
    );
  }, [setTodos]);

  const clearCompleted = useCallback(() => {
    setTodos((prev) => prev.filter((todo) => !todo.completed));
  }, [setTodos]);

  const filteredTodos = useMemo(() => {
    switch (filter) {
      case "active":
        return storeTodos.filter((t) => !t.completed);
      case "completed":
        return storeTodos.filter((t) => t.completed);
      default:
        return storeTodos;
    }
  }, [storeTodos, filter]);

  const stats: TodoStats = useMemo(
    () => ({
      total: storeTodos.length,
      completed: storeTodos.filter((t) => t.completed).length,
      active: storeTodos.filter((t) => !t.completed).length,
    }),
    [storeTodos]
  );

  return {
    todos: filteredTodos,
    allTodos: storeTodos,
    isLoaded: true,
    filter,
    setFilter,
    stats,
    addTodo,
    toggleTodo,
    removeTodo,
    editTodo,
    clearCompleted,
  };
}

src/lib/graphify-context.ts.content:
/**
 * Graphify Context — Shared codebase understanding layer.
 *
 * Provides typed access to graph.json + context.json so both
 * the AI assistant and the 3D visualisation can reason about the
 * project structure, dependencies, and functions in real time.
 */

export interface GraphNode {
  id: string;
  label: string;
  file_type: string;
  source_file: string;
  source_location: string;
  community: string | number;
  community_name: string;
}

export interface GraphLink {
  source: string;
  target: string;
  relation: string;
  confidence: string;
  source_file: string;
  source_location: string;
  weight: number;
  confidence_score: number;
}

export interface GraphData {
  directed: boolean;
  multigraph: boolean;
  graph: {
    community_labels: Record<string, string>;
  };
  nodes: GraphNode[];
  links: GraphLink[];
}

export interface FileEntry {
  id: string;
  type: string;
  client: boolean;
  exports: string[];
  imports: string[];
  importedBy: string[];
  content?: string;
}

export interface ContextData {
  generatedAt: string;
  projectRoot: string;
  summary: {
    totalFiles: number;
    clientComponents: number;
    pages: string[];
    layouts: string[];
    apiRoutes: string[];
  };
  files: Record<string, FileEntry>;
}

export interface GraphifyPayload {
  graph: GraphData;
  context: ContextData;
}

/* ---------- Colour palette per community ---------- */
const COMMUNITY_COLORS = [
  "#ef4444", "#f97316", "#f59e0b", "#84cc16", "#22c55e",
  "#10b981", "#14b8a6", "#06b6d4", "#0ea5e9", "#3b82f6",
  "#6366f1", "#8b5cf6", "#a855f7", "#d946ef", "#ec4899",
  "#f43f5e", "#94a3b8", "#64748b", "#475569", "#334155",
];

export function nodeColorByCommunity(community: string | number) {
  if (typeof community === "string") {
    let hash = 0;
    for (let i = 0; i < community.length; i++) {
      hash = community.charCodeAt(i) + ((hash << 5) - hash);
    }
    return COMMUNITY_COLORS[Math.abs(hash) % COMMUNITY_COLORS.length] ?? "#64748b";
  }
  return COMMUNITY_COLORS[community % COMMUNITY_COLORS.length] ?? "#64748b";
}

/* ---------- Type badge helpers ---------- */
const TYPE_EMOJI: Record<string, string> = {
  page: "📄",
  layout: "🖼️",
  styles: "🎨",
  code: "💻",
  tsx: "⚛️",
  ts: "📘",
  component: "🧩",
  hook: "🪝",
  util: "🔧",
};

export function emojiForType(t?: string) {
  return TYPE_EMOJI[t ?? "code"] ?? "📦";
}

/* ---------- AI helpers ---------- */

/** Return the file path that owns a graph node label */
export function resolveSourceFile(node: GraphNode, context: ContextData) {
  return (
    context.files[node.source_file]?.type ??
    node.file_type
  );
}

/** All exported symbols from a given file path */
export function exportsOfFile(path: string, context: ContextData) {
  return context.files[path]?.exports ?? [];
}

/** All files that import this file */
export function importedBy(path: string, context: ContextData) {
  return context.files[path]?.importedBy ?? [];
}

/** All files this file imports */
export function importsOf(path: string, context: ContextData) {
  return context.files[path]?.imports ?? [];
}

/** Direct neighbours of a node (1° links) */
export function getLinkedNodes(
  nodeId: string,
  graph: GraphData,
  maxDepth = 1
) {
  const visited = new Map<string, number>();
  visited.set(nodeId, 0);
  const queue: [string, number][] = [[nodeId, 0]];

  while (queue.length) {
    const [cur, depth] = queue.shift()!;
    if (depth >= maxDepth) continue;

    for (const link of graph.links) {
      const other =
        link.source === cur ? link.target : link.target === cur ? link.source : null;
      if (other && !visited.has(other)) {
        visited.set(other, depth + 1);
        queue.push([other, depth + 1]);
      }
    }
  }

  visited.delete(nodeId);
  return visited;
}

/** Flattened list of all communities with their member nodes */
export function communityBreakdown(graph: GraphData) {
  const map = new Map<string | number, GraphNode[]>();
  for (const n of graph.nodes) {
    const arr = map.get(n.community) ?? [];
    arr.push(n);
    map.set(n.community, arr);
  }
  return [...map.entries()].sort((a, b) => b[1].length - a[1].length);
}

/** Which files are pages / layouts / apiRoutes (from context) */
export function routeFiles(context: ContextData) {
  return Object.entries(context.files).filter(([, v]) =>
    ["page", "layout", "api"].includes(v.type)
  );
}

/** Generate a descriptive name for a community based on its members */
export function communityName(nodes: GraphNode[]) {
  const types = new Map<string, number>();
  let hasPage = false, hasLayout = false, hasApi = false, hasHook = false, hasComponent = false;
  for (const n of nodes) {
    types.set(n.file_type, (types.get(n.file_type) ?? 0) + 1);
    if (n.file_type === "page" || n.source_file?.includes("/page")) hasPage = true;
    if (n.file_type === "layout" || n.source_file?.includes("/layout")) hasLayout = true;
    if (n.file_type === "api" || n.source_file?.includes("/api")) hasApi = true;
    if (n.file_type === "hook" || n.label.endsWith("()") && (n.source_file?.includes("/hooks/") || n.source_file?.includes("use"))) hasHook = true;
    if (n.file_type === "component" || n.source_file?.includes("/components/")) hasComponent = true;
  }
  const sorted = [...types.entries()].sort((a, b) => b[1] - a[1]);
  const top = sorted[0]?.[0] ?? "";

  if (hasPage && hasLayout) return "App Shell";
  if (hasPage) return "Pages";
  if (hasLayout) return "Layouts";
  if (hasApi) return "API Routes";
  if (hasHook && hasComponent) return "UI + Hooks";
  if (hasComponent) return "UI Components";
  if (hasHook) return "Hooks & Utils";
  if (top === "styles" || top === "css") return "Styles";
  if (top === "code" && nodes.some((n) => n.source_file?.includes("config"))) return "Config";
  if (nodes.some((n) => n.source_file?.includes("lib/") || n.source_file?.includes("utils"))) return "Lib & Utils";
  if (nodes.some((n) => n.source_file?.includes("types"))) return "Types";
  return top ? top[0].toUpperCase() + top.slice(1) + "s" : "Mixed";
}

/** Files with the most dependents (most imported) */
export function topHubs(context: ContextData, limit = 10) {
  return Object.entries(context.files)
    .map(([path, f]) => ({ path, count: (f.importedBy ?? []).length, exports: f.exports ?? [] }))
    .sort((a, b) => b.count - a.count)
    .slice(0, limit);
}

src/lib/storage.ts.content:
// Shared storage library to abstract LocalStorage usage
export const StorageLib = {
  get: <T>(key: string, defaultValue: T): T => {
    if (typeof window === 'undefined') return defaultValue;
    try {
      const item = window.localStorage.getItem(key);
      return item ? (JSON.parse(item) as T) : defaultValue;
    } catch (error) {
      console.warn(`Error reading localStorage key "${key}":`, error);
      return defaultValue;
    }
  },

  set: <T>(key: string, value: T): void => {
    if (typeof window === 'undefined') return;
    try {
      window.localStorage.setItem(key, JSON.stringify(value));
    } catch (error) {
      console.warn(`Error setting localStorage key "${key}":`, error);
    }
  }
};

